import React from 'react'
import { Layout, Menu } from 'antd';
import { CommentOutlined } from "@ant-design/icons"
const { Header } = Layout;

const items = [
  {
    label: 'Chat',
    key: 'chat',
    icon: <CommentOutlined />
  },
  {
    label: 'Contacts'
  }
]
export default function Bar() {
  return (
    <Header
      style={{
        display: 'flex',
        alignItems: 'center',
        backgroundColor: 'rgb(9,14,13,0.8)',
        borderBottom: "1px solid black",
      }}
    >
      <Menu items={items} backgroundColor="transparent" mode='horizontal'/>
    </Header>
  )
}
